# E2-Skeptic three-route assess for S50-T1-A-E2
def assess(record: dict) -> str:
    required = {'tasks', 'rubric_levels', 'holdout', 'slices', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)
    except Exception:
        return 'REBUILD_EVAL_DATASET'
    return 'PASS' if ok else 'REBUILD_EVAL_DATASET'

record = {"case_id": "CASO-ICA-050-1A", **{"tasks":40,"slices":{"normal":25,"edge":10,"adversarial":5},"rubric_levels":{0,1,2,3},"holdout":10}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'holdout'}
print(assess(valid), assess(invalid), assess(incomplete))

